import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './CustomerDashboard.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerReturns = () => {
  const [returns, setReturns] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchReturns();
  }, []);

  const fetchReturns = async () => {
    try {
      const response = await axios.get(`${API_URL}/returns`);
      setReturns(response.data.data || response.data);
    } catch (error) {
      console.error('Error fetching returns:', error);
    } finally {
      setLoading(false);
    }
  };

  const getStatusClass = (status) => {
    switch(status) {
      case 'PENDING': return 'status-badge-table pending';
      case 'APPROVED': return 'status-badge-table approved';
      case 'REJECTED': return 'status-badge-table rejected';
      default: return 'status-badge-table';
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric'
    });
  };

  return (
    <div className="main-content">
      <div className="content-container">
        <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <h1>My Returns</h1>
            <p>Track your return requests</p>
          </div>
          <Link to="/customer/returns/create" className="btn-primary">
            Request Return
          </Link>
        </div>

        {loading ? (
          <div className="loading-spinner">Loading...</div>
        ) : returns.length === 0 ? (
          <div className="empty-state">No return requests found</div>
        ) : (
          <div className="card">
            <div className="table-responsive">
              <table className="transactions-table">
                <thead>
                  <tr>
                    <th>Return ID</th>
                    <th>Date</th>
                    <th>Rice Type</th>
                    <th>Quantity</th>
                    <th>Amount</th>
                    <th>Status</th>
                    <th>Reason</th>
                  </tr>
                </thead>
                <tbody>
                  {returns.map((returnReq) => (
                    <tr key={returnReq._id}>
                      <td>{returnReq.returnId}</td>
                      <td>{formatDate(returnReq.createdAt)}</td>
                      <td>{returnReq.riceType}</td>
                      <td>{returnReq.quantityKg} kg</td>
                      <td>₱{returnReq.amountPaid}</td>
                      <td>
                        <span className={getStatusClass(returnReq.status)}>
                          {returnReq.status}
                        </span>
                      </td>
                      <td>{returnReq.returnReason}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CustomerReturns;
